package com.banking.app.model;

import java.io.Serializable;
import java.math.BigDecimal;
import java.util.UUID;

public class Transaction implements Serializable {
    private final String transactionId;
    private final TransactionType type;
    private final BigDecimal amount;
    private final String fromAccountId;
    private final String toAccountId;
    private final String description;
    private final long timestamp;
    private TransactionStatus status;
    private String idempotencyKey;

    private Transaction(Builder builder) {
        this.transactionId = UUID.randomUUID().toString();
        this.type = builder.type;
        this.amount = builder.amount;
        this.fromAccountId = builder.fromAccountId;
        this.toAccountId = builder.toAccountId;
        this.description = builder.description;
        this.timestamp = System.currentTimeMillis();
        this.status = TransactionStatus.PENDING;
        this.idempotencyKey = builder.idempotencyKey != null ? builder.idempotencyKey : UUID.randomUUID().toString();
    }

    public String getTransactionId() { return transactionId; }
    public TransactionType getType() { return type; }
    public BigDecimal getAmount() { return amount; }
    public String getFromAccountId() { return fromAccountId; }
    public String getToAccountId() { return toAccountId; }
    public String getDescription() { return description; }
    public long getTimestamp() { return timestamp; }
    public TransactionStatus getStatus() { return status; }
    public void setStatus(TransactionStatus status) { this.status = status; }
    public String getIdempotencyKey() { return idempotencyKey; }

    public static class Builder {
        private TransactionType type;
        private BigDecimal amount;
        private String fromAccountId;
        private String toAccountId;
        private String description;
        private String idempotencyKey;

        public Builder type(TransactionType type) { this.type = type; return this; }
        public Builder amount(BigDecimal amount) { this.amount = amount; return this; }
        public Builder fromAccountId(String id) { this.fromAccountId = id; return this; }
        public Builder toAccountId(String id) { this.toAccountId = id; return this; }
        public Builder description(String desc) { this.description = desc; return this; }
        public Builder idempotencyKey(String key) { this.idempotencyKey = key; return this; }

        public Transaction build() {
            if (type == null || amount == null || fromAccountId == null) {
                throw new IllegalStateException("Transaction type, amount, and fromAccountId are required");
            }
            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                throw new IllegalArgumentException("Transaction amount must be positive");
            }
            if (type == TransactionType.TRANSFER && (toAccountId == null || toAccountId.isEmpty())) {
                throw new IllegalStateException("Transfer requires a destination account");
            }
            return new Transaction(this);
        }
    }
}

